"use client";

import * as React from "react";
import { cn } from "../lib/cn";

export type AccordionType = "single" | "multiple";

export type AccordionItem = {
  content: React.ReactNode;
  disabled?: boolean;
  title: React.ReactNode;
  value: string;
};

export type AccordionProps = React.HTMLAttributes<HTMLDivElement> & {
  defaultValue?: string | string[];
  items: readonly AccordionItem[];
  onValueChange?: (value: string | string[]) => void;
  type?: AccordionType;
  value?: string | string[];
};

function toArray(value: string | string[] | undefined) {
  if (value === undefined) return [];
  return Array.isArray(value) ? value : [value];
}

export function Accordion({
  className,
  defaultValue,
  items,
  onValueChange,
  type = "single",
  value,
  ...props
}: AccordionProps) {
  const [internalValue, setInternalValue] = React.useState<string[]>(() => toArray(defaultValue));
  const selectedValues = value === undefined ? internalValue : toArray(value);

  function updateValue(nextValues: string[]) {
    if (value === undefined) setInternalValue(nextValues);
    onValueChange?.(type === "single" ? (nextValues[0] ?? "") : nextValues);
  }

  function toggleItem(item: AccordionItem) {
    if (item.disabled) return;
    const isOpen = selectedValues.includes(item.value);
    if (type === "single") {
      updateValue(isOpen ? [] : [item.value]);
      return;
    }
    updateValue(
      isOpen
        ? selectedValues.filter((selectedValue) => selectedValue !== item.value)
        : [...selectedValues, item.value]
    );
  }

  return (
    <div
      className={cn(
        "overflow-hidden rounded-axie-card border border-axie-line bg-axie-surface",
        className
      )}
      {...props}
    >
      {items.map((item) => {
        const isOpen = selectedValues.includes(item.value);
        return (
          <div className="border-b border-axie-line last:border-b-0" key={item.value}>
            <button
              aria-expanded={isOpen}
              className={cn(
                "flex min-h-12 w-full items-center justify-between gap-4 px-axie-md py-3 text-left text-[14px] font-black text-axie-ink outline-none axie-pressable focus-visible:bg-axie-surface-soft/68 focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-axie-accent/28",
                item.disabled
                  ? "cursor-not-allowed opacity-50"
                  : "hover:bg-axie-surface-soft/62 active:bg-axie-surface-soft"
              )}
              disabled={item.disabled}
              type="button"
              onClick={() => toggleItem(item)}
            >
              <span>{item.title}</span>
              <span
                aria-hidden
                className={cn(
                  "grid h-6 w-6 shrink-0 place-items-center rounded-full border border-axie-line text-[16px] leading-none text-axie-muted transition duration-300 ease-[var(--axie-motion-spring)]",
                  isOpen ? "rotate-45 bg-axie-ink text-axie-surface" : "bg-axie-surface"
                )}
              >
                +
              </span>
            </button>
            {isOpen ? (
              <div className="border-t border-axie-line bg-axie-surface-soft/36 px-axie-md py-axie-md text-[14px] font-bold leading-6 text-axie-muted animate-[axie-accordion-down_var(--axie-motion-base)_var(--axie-motion-spring)_both]">
                {item.content}
              </div>
            ) : null}
          </div>
        );
      })}
    </div>
  );
}

type ClassValue = string | false | null | undefined;

export function cn(...values: ClassValue[]) {
  return values.filter(Boolean).join(" ");
}

@theme inline {
  --color-axie-ink: var(--axie-color-ink);
  --color-axie-paper: var(--axie-color-paper);
  --color-axie-surface: var(--axie-color-surface);
  --color-axie-surface-soft: var(--axie-color-surface-soft);
  --color-axie-muted: var(--axie-color-muted);
  --color-axie-line: var(--axie-color-line);
  --color-axie-accent: var(--axie-color-accent);
  --color-axie-accent-soft: var(--axie-color-accent-soft);
  --color-axie-danger: var(--axie-color-danger);
  --color-axie-danger-soft: var(--axie-color-danger-soft);
  --color-axie-warning: var(--axie-color-warning);
  --color-axie-warning-soft: var(--axie-color-warning-soft);
  --color-axie-info: var(--axie-color-info);
  --color-axie-info-soft: var(--axie-color-info-soft);
  --radius-axie-card: var(--axie-radius-card);
  --radius-axie-control: var(--axie-radius-control);
  --radius-axie-sheet: var(--axie-radius-sheet);
  --radius-axie-pill: var(--axie-radius-pill);
  --spacing-axie-page: var(--axie-space-page);
  --spacing-axie-xs: var(--axie-space-xs);
  --spacing-axie-sm: var(--axie-space-sm);
  --spacing-axie-md: var(--axie-space-md);
  --spacing-axie-lg: var(--axie-space-lg);
  --spacing-axie-xl: var(--axie-space-xl);
  --spacing-axie-2xl: var(--axie-space-2xl);
  --shadow-axie-raised: 0 16px 36px color-mix(in srgb, var(--axie-color-ink) 10%, transparent);
  --shadow-axie-soft: 0 10px 24px color-mix(in srgb, var(--axie-color-ink) 6%, transparent);
  --shadow-axie-nav: 0 16px 38px color-mix(in srgb, var(--axie-color-ink) 12%, transparent);
}

:root {
  --axie-color-ink: #263024;
  --axie-color-paper: #f4f1e6;
  --axie-color-surface: #fffdf4;
  --axie-color-surface-soft: #e8ead6;
  --axie-color-muted: #68705d;
  --axie-color-line: #d7d2b9;
  --axie-color-accent: #6f7f3f;
  --axie-color-accent-soft: #e0e8c7;
  --axie-color-danger: #a45447;
  --axie-color-danger-soft: #efd8d0;
  --axie-color-warning: #947236;
  --axie-color-warning-soft: #ecdcb8;
  --axie-color-info: #4d6972;
  --axie-color-info-soft: #dce8e6;
  --axie-radius-card: 10px;
  --axie-radius-control: 12px;
  --axie-radius-sheet: 30px;
  --axie-radius-pill: 999px;
  --axie-space-page: 20px;
  --axie-space-xs: 6px;
  --axie-space-sm: 10px;
  --axie-space-md: 14px;
  --axie-space-lg: 20px;
  --axie-space-xl: 28px;
  --axie-space-2xl: 36px;
  --axie-motion-fast: 160ms;
  --axie-motion-base: 240ms;
  --axie-motion-slow: 360ms;
  --axie-motion-ease: cubic-bezier(0.2, 0.9, 0.2, 1);
  --axie-motion-spring: cubic-bezier(0.16, 1, 0.3, 1);
  --axie-motion-pop: cubic-bezier(0.18, 1.24, 0.3, 1);
}

.axie-pressable {
  transform: translate3d(0, 0, 0) scale(1);
  transition-duration: var(--axie-motion-base);
  transition-property: background-color, border-color, box-shadow, color, opacity, transform;
  transition-timing-function: var(--axie-motion-spring);
  will-change: transform;
}

.axie-pressable:hover {
  transform: translate3d(0, -1px, 0) scale(1.005);
}

.axie-pressable:active {
  transform: translate3d(0, 0, 0) scale(0.985);
}

.axie-enter {
  animation: axie-enter var(--axie-motion-slow) var(--axie-motion-spring) both;
}

.axie-pop {
  animation: axie-pop var(--axie-motion-slow) var(--axie-motion-pop) both;
}

.axie-fade {
  animation: axie-fade var(--axie-motion-base) ease-out both;
}

.axie-sheet-backdrop {
  animation: axie-fade var(--axie-motion-fast) ease-out both;
}

.axie-sheet-panel {
  animation: axie-sheet-panel-in var(--axie-motion-slow) var(--axie-motion-ease) both;
}

.axie-row-enter {
  animation: axie-row-in var(--axie-motion-base) var(--axie-motion-ease) both;
  animation-delay: var(--axie-row-delay, 0ms);
}

@keyframes axie-fade {
  from {
    opacity: 0;
  }
  to {
    opacity: 1;
  }
}

@keyframes axie-enter {
  from {
    opacity: 0;
    transform: translate3d(0, 10px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-pop {
  from {
    opacity: 0;
    transform: translate3d(0, 12px, 0) scale(0.96);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-sheet-panel-in {
  from {
    opacity: 0.72;
    transform: translate3d(0, 26px, 0) scale(0.985);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0) scale(1);
  }
}

@keyframes axie-row-in {
  from {
    opacity: 0;
    transform: translate3d(0, 8px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-accordion-down {
  from {
    opacity: 0;
    transform: translate3d(0, -4px, 0);
  }
  to {
    opacity: 1;
    transform: translate3d(0, 0, 0);
  }
}

@keyframes axie-shimmer {
  100% {
    transform: translateX(100%);
  }
}

@keyframes axie-pulse-dot {
  0%,
  100% {
    box-shadow: 0 0 0 0 color-mix(in srgb, var(--axie-color-accent) 30%, transparent);
  }
  50% {
    box-shadow: 0 0 0 5px color-mix(in srgb, var(--axie-color-accent) 0%, transparent);
  }
}

@media (prefers-reduced-motion: reduce) {
  *,
  *::before,
  *::after {
    animation-duration: 0.001ms !important;
    animation-iteration-count: 1 !important;
    scroll-behavior: auto !important;
    transition-duration: 0.001ms !important;
  }

  .axie-enter,
  .axie-pop,
  .axie-fade,
  .axie-sheet-backdrop,
  .axie-sheet-panel,
  .axie-row-enter {
    animation: none;
  }

  .axie-pressable,
  .axie-pressable:hover,
  .axie-pressable:active {
    transform: none;
  }
}
